-- Seed experiences with real-looking data
-- We reference region_id and category_id by subquery since UUIDs are auto-generated

insert into public.experiences (title, slug, excerpt, description, region_id, category_id, price_cents, original_price_cents, duration_hours, max_guests, min_age, rating, review_count, featured, best_seller, image_url, gallery, includes, excludes, highlights, meeting_point, status)
